INSERT INTO `conversation_turns` VALUES ('61', '816d8b0b-c6a0-4833-b70f-0b03643b426b', 'alice', 'browser-20260612-20260612011845-q02', '1', 'qwen', '0', '有没有 87 键的机械键盘？是什么轴，多少钱？', '目前商城中暂时没有搜索到具体的87键机械键盘商品，知识库中也缺乏该类产品的详细轴体类型和实时价格信息。\n\n通常87键机械键盘（也称为TKL布局）会配备多种轴体，如红轴（线性、静音）、青轴（段落感强、清脆）、茶轴（轻微段落感、通用）等，价格范围一般在200元到1000元以上，具体取决于品牌、轴体品牌和做工材质。\n\n如果您有偏好的品牌或预算范围，我可以尝试再次为您精确搜索，或者您可以直接访问电商平台查看最新款式和实时报价。', 'COMPLETED', null, '{\"mediaCount\": 0}', '2026-06-12 01:18:50.483', '2026-06-12 01:19:02.295');
INSERT INTO `conversation_turns` VALUES ('62', '7fc24212-1887-4042-8c21-4305e3fcd585', 'alice', 'browser-20260612-20260612011845-q03', '1', 'qwen', '0', 'Aster 的黑色保温杯是多大容量，价格是多少？', '目前在商品库和商城中暂未检索到“Aster”品牌的黑色保温杯相关信息，因此无法提供其具体容量和价格。\n\n您可以确认一下品牌名称是否准确，或者是否有其他关键词（如型号、系列名）可以提供？这样我可以更精准地为您查找。', 'COMPLETED', null, '{\"mediaCount\": 0}', '2026-06-12 01:19:02.350', '2026-06-12 01:19:11.513');
INSERT INTO `conversation_turns` VALUES ('63', '8ce0d9ff-124e-4a04-99c5-a7cb1d480dad', 'alice', 'browser-20260612-20260612011845-q04', '1', 'qwen', '0', '猫粮 10kg 的那款还有多少库存？', '10kg 的猫粮目前库存有 200 件。', 'COMPLETED', null, '{\"mediaCount\": 0}', '2026-06-12 01:19:11.559', '2026-06-12 01:19:16.926');
